import { motion, useMotionTemplate, useMotionValue, animate } from 'framer-motion';
import { useEffect } from 'react';
import { FaBrain, FaShieldAlt, FaChartLine } from 'react-icons/fa';
import { FiArrowRight, FiPlay } from 'react-icons/fi';

const Hero = () => {
  // Animated gradient values
  const color = useMotionValue(0);
  const backgroundImage = useMotionTemplate`linear-gradient(to right, hsl(${color}, 80%, 60%), hsl(${color}, 80%, 50%)`;

  useEffect(() => {
    animate(color, 360, {
      duration: 20,
      repeat: Infinity,
      ease: 'linear',
    });
  }, []);

  return (
    <section className="relative overflow-hidden bg-gray-900 min-h-[90vh] flex items-center">
      {/* Animated particles */}
      <div className="absolute inset-0 overflow-hidden opacity-20">
        {[...Array(30)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute rounded-full bg-purple-500"
            style={{
              width: `${Math.random() * 10 + 2}px`,
              height: `${Math.random() * 10 + 2}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, (Math.random() - 0.5) * 100],
              y: [0, (Math.random() - 0.5) * 100],
              opacity: [0.1, 0.8, 0.1],
            }}
            transition={{
              duration: 10 + Math.random() * 20,
              repeat: Infinity,
              repeatType: 'reverse',
            }}
          />
        ))}
      </div>

      {/* Neural network grid */}
      <div className="absolute inset-0 [mask-image:radial-gradient(ellipse_at_center,black,transparent_70%)]">
        <div className="absolute inset-0 [background-image:linear-gradient(to_right,rgba(255,255,255,0.1)_1px,transparent_1px),linear-gradient(to_bottom,rgba(255,255,255,0.1)_1px,transparent_1px)] bg-[size:40px_40px] opacity-10" />
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-24 grid lg:grid-cols-2 gap-16 items-center">
        {/* Content */}
        <div className="relative z-10">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="inline-flex items-center px-4 py-2 rounded-full bg-white/5 backdrop-blur-sm border border-white/10 mb-8"
          >
            <FaBrain className="text-purple-400 mr-2" />
            <span className="text-sm font-medium text-white">NEURAL NETWORK v4.2</span>
          </motion.div>

          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            <span className="block">Decoding</span>
            <motion.span 
              className="block bg-clip-text text-transparent"
              style={{ backgroundImage }}
            >
              Digital Authenticity
            </motion.span>
          </motion.h1>

          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.6 }}
          >
            Our quantum-inspired AI detects the subtlest deepfake artifacts with 99.9% accuracy, powered by patented holographic analysis.
          </motion.p>

          <motion.div 
            className="flex flex-col sm:flex-row gap-4 mb-12"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="/demo"
              className="flex items-center justify-center gap-3 text-white px-6 py-4 rounded-xl font-medium shadow-lg hover:shadow-xl transition-all group relative overflow-hidden"
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.98 }}
            >
              <span className="absolute inset-0 bg-gradient-to-r from-purple-600 to-blue-500 group-hover:from-purple-500 group-hover:to-blue-400 transition-all" />
              <span className="relative z-10 flex items-center">
                Analyze Content <FiArrowRight className="ml-2 group-hover:translate-x-1 transition-transform" />
              </span>
            </motion.a>

            <motion.a
              href="#tech"
              className="flex items-center justify-center gap-3 text-white px-6 py-4 rounded-xl font-medium border border-white/20 hover:bg-white/10 transition-colors"
              whileHover={{ y: -2 }}
            >
              <FiPlay /> Tech Overview
            </motion.a>
          </motion.div>

          {/* Stats */}
          <motion.div 
            className="grid grid-cols-3 gap-4 max-w-md"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1 }}
          >
            {[
              { icon: <FaShieldAlt className="text-purple-400" />, value: "99.9%", label: "Accuracy" },
              { icon: <FaChartLine className="text-blue-400" />, value: "0.2s", label: "Analysis" },
              { icon: <FaBrain className="text-cyan-400" />, value: "10B+", label: "Models" }
            ].map((stat, i) => (
              <motion.div 
                key={i}
                className="bg-white/5 backdrop-blur-sm p-4 rounded-xl border border-white/10"
                whileHover={{ y: -5 }}
              >
                <div className="text-2xl font-bold text-white">{stat.value}</div>
                <div className="flex items-center mt-2 text-sm text-gray-300">
                  {stat.icon} <span className="ml-2">{stat.label}</span>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </div>

        {/* AI Visualizer */}
        <div className="relative h-full min-h-[400px]">
          <div className="absolute inset-0 rounded-3xl overflow-hidden border border-white/10 bg-gradient-to-br from-purple-900/30 to-blue-900/20 backdrop-blur-lg">
            {/* Holographic grid */}
            <div className="absolute inset-0 [background-image:linear-gradient(to_right,rgba(255,255,255,0.05)_1px,transparent_1px),linear-gradient(to_bottom,rgba(255,255,255,0.05)_1px,transparent_1px)] bg-[size:40px_40px]" />
            
            {/* Central AI core */}
            <div className="absolute inset-0 flex items-center justify-center">
              <motion.div 
                className="relative w-64 h-64"
                animate={{
                  rotate: 360
                }}
                transition={{
                  duration: 40,
                  repeat: Infinity,
                  ease: 'linear'
                }}
              >
                {/* Orbiting nodes */}
                {[...Array(6)].map((_, i) => (
                  <motion.div
                    key={i}
                    className="absolute top-0 left-1/2 h-full w-1 origin-bottom"
                    style={{
                      rotate: i * 60
                    }}
                  >
                    <div className="relative h-8 w-8 -translate-x-1/2">
                      <motion.div
                        className="h-full w-full rounded-full bg-gradient-to-br from-purple-500 to-blue-400 shadow-lg shadow-purple-500/30"
                        animate={{
                          scale: [1, 1.2, 1],
                          opacity: [0.8, 1, 0.8]
                        }}
                        transition={{
                          duration: 2 + i,
                          repeat: Infinity
                        }}
                      />
                    </div>
                  </motion.div>
                ))}
              </motion.div>
            </div>

            {/* Scanning beam */}
            <motion.div
              className="absolute top-0 left-0 w-full h-0.5 bg-gradient-to-r from-transparent via-cyan-400/80 to-transparent"
              animate={{
                y: ['0%', '100%']
              }}
              transition={{
                duration: 4,
                repeat: Infinity,
                ease: 'linear'
              }}
            />

            {/* Floating analysis cards */}
            {[
              { text: "Facial Micro-Expressions", x: "20%", y: "30%", delay: 0 },
              { text: "Pixel-Level Artifacts", x: "70%", y: "20%", delay: 0.5 },
              { text: "Spectral Analysis", x: "30%", y: "70%", delay: 1 }
            ].map((card, i) => (
              <motion.div
                key={i}
                className="absolute bg-white/5 backdrop-blur-sm px-4 py-3 rounded-lg border border-white/10 text-sm text-white shadow-lg"
                style={{
                  left: card.x,
                  top: card.y
                }}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{
                  delay: 1.2 + card.delay,
                  duration: 0.6
                }}
              >
                {card.text}
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
